//! Memory Node: 记忆树中的单个节点\n//!\n//! 每个 MemoryNode 代表一个记忆单位，支持：\n//! - 分层结构（父子关系）\n//! - Token 计数和压缩\n//! - 元数据存储\n//! - 相关性评分\n\nuse chrono::{DateTime, Utc};\nuse serde::{Deserialize, Serialize};\nuse std::collections::HashMap;\n\n/// 记忆节点\n#[derive(Debug, Clone, Serialize, Deserialize)]\npub struct MemoryNode {\n    /// 唯一标识\n    pub node_id: String,\n\n    /// 父节点 ID（分层结构）\n    pub parent_id: Option<String>,\n\n    /// 子节点 ID 列表\n    pub child_ids: Vec<String>,\n\n    /// 节点内容\n    pub content: String,\n\n    /// Token 计数\n    pub token_count: usize,\n\n    /// 相关性评分 (0.0 - 1.0)\n    pub score: f32,\n\n    /// 来源引用（gmail, slack, personal, etc.)\n    pub source_ref: String,\n\n    /// 创建时间\n    pub created_at: DateTime<Utc>,\n\n    /// 更新时间\n    pub updated_at: DateTime<Utc>,\n\n    /// 元数据（灵活存储额外信息）\n    pub metadata: HashMap<String, String>,\n\n    /// 是否被标记为重要\n    pub is_important: bool,\n\n    /// 访问计数\n    pub access_count: u32,\n\n    /// 上次访问时间\n    pub last_accessed: Option<DateTime<Utc>>,\n}\n\nimpl MemoryNode {\n    /// 创建新的记忆节点\n    pub fn new(content: String, source_ref: String) -> Self {\n        let now = Utc::now();\n        let token_count = Self::estimate_tokens(&content);\n\n        Self {\n            node_id: uuid::Uuid::new_v4().to_string(),\n            parent_id: None,\n            child_ids: Vec::new(),\n            content,\n            token_count,\n            score: 1.0,\n            source_ref,\n            created_at: now,\n            updated_at: now,\n            metadata: HashMap::new(),\n            is_important: false,\n            access_count: 0,\n            last_accessed: None,\n        }\n    }\n\n    /// 估算 token 数量（简单实现）\n    /// 实际应用中可以使用更精确的 tokenizer\n    pub fn estimate_tokens(text: &str) -> usize {\n        // 粗略估计：平均 4 个字符 = 1 token\n        (text.len() + 3) / 4\n    }\n\n    /// 添加元数据\n    pub fn add_metadata(&mut self, key: String, value: String) {\n        self.metadata.insert(key, value);\n    }\n\n    /// 设置重要标记\n    pub fn mark_important(&mut self) {\n        self.is_important = true;\n    }\n\n    /// 记录访问\n    pub fn record_access(&mut self) {\n        self.access_count += 1;\n        self.last_accessed = Some(Utc::now());\n    }\n\n    /// 计算相关性评分（基于多个因素）\n    pub fn calculate_relevance_score(&self) -> f32 {\n        let mut score = self.score;\n\n        // 重要标记增加权重\n        if self.is_important {\n            score *= 1.5;\n        }\n\n        // 访问频率增加权重\n        score *= 1.0 + (self.access_count as f32 * 0.1);\n\n        // 新鲜度（越近期创建权重越高）\n        let age_days = (Utc::now() - self.created_at).num_days();\n        if age_days < 7 {\n            score *= 1.2;\n        }\n\n        // 限制在 0.0 - 1.0 范围内\n        score.min(1.0)\n    }\n\n    /// 获取节点的简要摘要\n    pub fn get_summary(&self, max_chars: usize) -> String {\n        if self.content.len() <= max_chars {\n            self.content.clone()\n        } else {\n            format!(\"{}...\", &self.content[..max_chars])\n        }\n    }\n\n    /// 序列化为 JSON（用于数据库存储）\n    pub fn to_json(&self) -> String {\n        serde_json::to_string(self).unwrap_or_default()\n    }\n\n    /// 从 JSON 反序列化\n    pub fn from_json(json: &str) -> Result<Self, serde_json::Error> {\n        serde_json::from_str(json)\n    }\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn test_create_memory_node() {\n        let node = MemoryNode::new(\n            \"Test memory content\".to_string(),\n            \"test_source\".to_string(),\n        );\n\n        assert!(!node.node_id.is_empty());\n        assert_eq!(node.content, \"Test memory content\");\n        assert_eq!(node.source_ref, \"test_source\");\n        assert!(node.token_count > 0);\n    }\n\n    #[test]\n    fn test_token_estimation() {\n        let token_count = MemoryNode::estimate_tokens(\"Hello world\");\n        assert!(token_count > 0);\n    }\n\n    #[test]\n    fn test_metadata() {\n        let mut node = MemoryNode::new(\"Test\".to_string(), \"test\".to_string());\n        node.add_metadata(\"key1\".to_string(), \"value1\".to_string());\n        assert_eq!(node.metadata.get(\"key1\"), Some(&\"value1\".to_string()));\n    }\n\n    #[test]\n    fn test_importance_marking() {\n        let mut node = MemoryNode::new(\"Test\".to_string(), \"test\".to_string());\n        assert!(!node.is_important);\n        node.mark_important();\n        assert!(node.is_important);\n    }\n\n    #[test]\n    fn test_access_tracking() {\n        let mut node = MemoryNode::new(\"Test\".to_string(), \"test\".to_string());\n        assert_eq!(node.access_count, 0);\n        node.record_access();\n        assert_eq!(node.access_count, 1);\n        assert!(node.last_accessed.is_some());\n    }\n\n    #[test]\n    fn test_relevance_score_calculation() {\n        let mut node = MemoryNode::new(\"Test\".to_string(), \"test\".to_string());\n        node.mark_important();\n        node.record_access();\n        let score = node.calculate_relevance_score();\n        assert!(score > 1.0);\n    }\n\n    #[test]\n    fn test_summary() {\n        let content = \"This is a long memory content that should be truncated\".to_string();\n        let node = MemoryNode::new(content.clone(), \"test\".to_string());\n        let summary = node.get_summary(20);\n        assert!(summary.contains(\"...\"));\n    }\n\n    #[test]\n    fn test_json_serialization() {\n        let node = MemoryNode::new(\"Test content\".to_string(), \"test\".to_string());\n        let json = node.to_json();\n        let deserialized = MemoryNode::from_json(&json).unwrap();\n        assert_eq!(node.node_id, deserialized.node_id);\n        assert_eq!(node.content, deserialized.content);\n    }\n}\n"